+  mgr_->getLogger()->info(DPL, 903, 
+                         "Adaptive congestion weight: avg_hpwl_delta={:.2f}, avg_cong_improvement={:.6f}, "
+                         "samples={}, weight={:.3f}", 
+                         avg_hpwl_delta, avg_cong_improvement, valid_samples, adaptive_weight);
+  
+  return adaptive_weight;
