    bool operator()(Node* p, Node* q) const
    {
      return p->getCenterX() < q->getCenterX();
    }
    bool operator()(Node*& s, DbuX i) const { return s->getCenterX() < i; }
    bool operator()(DbuX i, Node*& s) const { return i < s->getCenterX(); }
  };

